/* wms-master-itemctg-sql-oracle.xml - insertInterfaceItemCategory */
INSERT INTO TWORK_INTF_CTG_RCV (
	   CTKEY			/* 센터코드 */
	 , OWKEY			/* 화주코드 */
	 , CTGKEY			/* 카테고리코드 */
	 , CTGNM			/* 카테고리명 */
	 , CTGLV			/* 상품대중소구분 */
	 , UPRCTGKEY		/* 상위상품분류 */
	 , DELYN			/* 삭제여부 */
	 , PRCSYN			/* 처리여부 */
	 , PRCSDATE			/* 처리일시 */
	 , RCVDATE			/* 수신일시 */
	 , INSERTDATE		/* 입력일시 */
	 , INSERTURKEY		/* 입력자 */
	 , UPDATEDATE		/* 수정일시 */
	 , UPDATEURKEY		/* 수정자 */
	 )
VALUES (
	   #{ctkey}
	 , #{owkey}
	 , #{ctgkey}
	 , #{ctgnm}
	 , #{ctglv}
	 , #{uprctgkey}
	 , #{delyn}
	 , 'N'
	 , NULL
	 , #{sysdate}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

/* wms-master-itemctg-sql-oracle.xml - insertTworkMstCtg */
INSERT INTO TWORK_MST_CTG (
	   CTKEY			/* 센터코드 */
	 , OWKEY			/* 화주 */
	 , CTGKEY			/* 상품대/중/소코드 */
	 , CTGLV			/* 상품대/중/소구분 */
	 , CTGNM			/* 상품대/중/소명 */
	 , UPRCTGKEY		/* 상위상품분류 */
	 , CLOSDATE			/* 종료일시 */
	 , DELYN			/* 삭제여부 */
	 , INSERTDATE		/* 입력일시 */
	 , INSERTURKEY		/* 입력사용자 */
	 , UPDATEDATE		/* 수정일시 */
	 , UPDATEURKEY		/* 수정사용자 */
	 )
VALUES (
	   #{ctkey}
	 , #{owkey}
	 , #{ctgkey}
	 , #{ctglv}
	 , #{ctgnm}
	 , #{uprctgkey}
	 , '29991231235959'
	 , COALESCE(#{delyn}, 'N')
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )
